/* ═══════════════════════════════════════════════════════════════════════════
   AURA ALPHA — Rewards Dashboard
   Active rewards, history, and monthly prize pool overview.
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useEffect } from 'react';
import { api } from '../utils/api';
import { motion } from 'framer-motion';
import styles from './RewardsPage.module.css';

const REWARD_ICONS = {
  agent_slots: '\u{1F916}',
  premium_strategies: '\u{1F4CA}',
  badge: '\u{1F3C5}',
  featured_trader: '\u2B50',
  discount: '\u{1F4B0}',
};

const BADGE_COLORS = { gold: '#D29922', silver: '#8B949E', bronze: '#CD7F32' };

const MONTHLY_PRIZES = [
  { rank: '#1', rewards: ['+2 Agent Slots', 'All Premium Strategies', 'Gold Badge', 'Featured Trader'], color: '#D29922' },
  { rank: '#2-3', rewards: ['+1 Agent Slot', 'All Premium Strategies', 'Silver Badge'], color: '#8B949E' },
  { rank: '#4-5', rewards: ['All Premium Strategies', 'Bronze Badge'], color: '#CD7F32' },
];

export default function RewardsPage() {
  const [active, setActive] = useState([]);
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [tab, setTab] = useState('active');

  useEffect(() => {
    (async () => {
      try {
        const [a, h] = await Promise.all([
          api('/rewards/active', { silent: true }).catch(() => ({ rewards: [] })),
          api('/rewards/history', { silent: true }).catch(() => ({ rewards: [] })),
        ]);
        setActive(a?.rewards || []);
        setHistory(h?.rewards || []);
      } catch {}
      setLoading(false);
    })();
  }, []);

  return (
    <div className={styles.page}>
      <div className={styles.header}>
        <h1 className={styles.title}>Rewards</h1>
        <p className={styles.subtitle}>Earn rewards by ranking on the leaderboard and winning tournaments.</p>
      </div>

      {/* Monthly Prize Pool */}
      <div className={styles.prizeSection}>
        <h3 className={styles.sectionTitle}>Monthly Prize Pool</h3>
        <p className={styles.sectionDesc}>Top 5 traders each month earn time-limited rewards. Minimum 30 trades to qualify.</p>
        <div className={styles.prizeGrid}>
          {MONTHLY_PRIZES.map((p, i) => (
            <motion.div
              key={i}
              className={styles.prizeCard}
              style={{ borderColor: p.color + '44' }}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.1 }}
            >
              <div className={styles.prizeRank} style={{ color: p.color }}>{p.rank}</div>
              <ul className={styles.prizeList}>
                {p.rewards.map((r, j) => <li key={j}>{r}</li>)}
              </ul>
              <div className={styles.prizeDuration}>30-day rewards</div>
            </motion.div>
          ))}
        </div>
      </div>

      {/* Tabs */}
      <div className={styles.tabs}>
        <button className={`${styles.tab} ${tab === 'active' ? styles.tabActive : ''}`} onClick={() => setTab('active')}>
          Active Rewards {active.length > 0 && <span className={styles.badge}>{active.length}</span>}
        </button>
        <button className={`${styles.tab} ${tab === 'history' ? styles.tabActive : ''}`} onClick={() => setTab('history')}>
          History
        </button>
      </div>

      {/* Active Rewards */}
      {tab === 'active' && (
        <div className={styles.rewardList}>
          {loading ? (
            [1,2,3].map(i => <div key={i} className={styles.skeleton} />)
          ) : active.length === 0 ? (
            <div className={styles.empty}>
              <p className={styles.emptyTitle}>No active rewards</p>
              <p className={styles.emptyDesc}>Climb the leaderboard or win a tournament to earn rewards.</p>
            </div>
          ) : (
            active.map((r, i) => (
              <motion.div
                key={r.id}
                className={styles.rewardCard}
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: i * 0.05 }}
              >
                <span className={styles.rewardIcon}>{REWARD_ICONS[r.type] || '\u{1F381}'}</span>
                <div className={styles.rewardInfo}>
                  <div className={styles.rewardLabel}>{r.label}</div>
                  <div className={styles.rewardSource}>
                    {r.source === 'tournament' ? 'Tournament' : 'Monthly Leaderboard'}
                  </div>
                </div>
                {r.days_remaining !== null && (
                  <div className={`${styles.rewardTimer} ${r.expires_soon ? styles.expiringSoon : ''}`}>
                    {r.days_remaining}d left
                  </div>
                )}
                {r.days_remaining === null && (
                  <div className={styles.rewardPermanent}>Permanent</div>
                )}
              </motion.div>
            ))
          )}
        </div>
      )}

      {/* History */}
      {tab === 'history' && (
        <div className={styles.rewardList}>
          {history.length === 0 ? (
            <div className={styles.empty}>
              <p className={styles.emptyTitle}>No reward history yet</p>
            </div>
          ) : (
            history.map((r, i) => (
              <div key={r.id} className={`${styles.rewardCard} ${!r.active ? styles.expired : ''}`}>
                <span className={styles.rewardIcon}>{REWARD_ICONS[r.type] || '\u{1F381}'}</span>
                <div className={styles.rewardInfo}>
                  <div className={styles.rewardLabel}>{r.label}</div>
                  <div className={styles.rewardSource}>{r.source}</div>
                </div>
                <div className={r.active ? styles.rewardActive : styles.rewardExpired}>
                  {r.active ? 'Active' : 'Expired'}
                </div>
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
}
